import { useState } from "react";
import "./App.css";
import Cart from "./Cart";

function App() {
  const [page, setPage] = useState("home");
  const [cartItems, setCartItems] = useState([]);

  return (
    <div>
      <Header setPage={setPage} cartItems={cartItems} />

      {page === "home" && <Home />}
      {page === "delivery" && <DeliveryAreas />}
      {page === "fitness" && (
        <FitnessPage cartItems={cartItems} setCartItems={setCartItems} setPage={setPage} />
      )}
      {page === "cart" && (
        <Cart cartItems={cartItems} setCartItems={setCartItems} setPage={setPage} />
      )}

      <Footer />
    </div>
  );
}

function Header({ setPage, cartItems }) {
  const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <header className="header">
      <div className="logo" onClick={() => setPage("home")}>RentNest</div>

      <nav>
        <div className="dropdown">
          <a>KITCHEN ▼</a>
          <div className="dropdown-menu">
            <p>Fridges</p><p>Freezers</p><p>Microwaves</p><p>Dishwashers</p>
          </div>
        </div>

        <div className="dropdown">
          <a>LAUNDRY ▼</a>
          <div className="dropdown-menu">
            <p>Washing Machines</p><p>Dryers</p><p>Dehumidifiers</p><p>Vacuum Cleaners</p>
          </div>
        </div>

        <div className="dropdown">
          <a>FURNITURE ▼</a>
          <div className="dropdown-menu">
            <p>Furniture Packages</p><p>Lounge</p><p>Bedroom</p><p>Dining</p><p>Office Furniture</p>
          </div>
        </div>

        <a onClick={() => setPage("fitness")}>FITNESS</a>
        <a onClick={() => setPage("delivery")}>DELIVERY AREAS</a>
        <a onClick={() => setPage("cart")}>🛒 CART ({cartCount})</a>
      </nav>

      <div className="header-right">
        <button className="login-btn">LOGIN</button>
        <button className="signup-btn">SIGN UP</button>
        <div className="phone">📞 0800 111 313</div>
      </div>
    </header>
  );
}

function Home() {
  return (
    <>
      <section className="features">
        <div>↩️ Flexible Rental</div>
        <div>💲 Affordable Solutions</div>
        <div>✅ Fast Approval</div>
        <div>🔧 Replace or Repair</div>
      </section>

      <section className="hero">
        <div>
          <h1>New Zealand's Trusted Provider of Furniture and Appliance Rental Solutions.</h1>
          <button>CONTACT US</button>
        </div>
        <div className="hero-text">
          <p>Whether it's appliance rentals, furniture rentals, or fitness equipment, RentNest has you covered.</p>
          <p>We make renting quick, easy and affordable.</p>
        </div>
      </section>
    </>
  );
}

function FitnessPage({ cartItems, setCartItems, setPage }) {
  const products = [
    {
      id: 1,
      name: "Exercise Bike",
      priceNumber: 14,
      img: "https://images.unsplash.com/photo-1591741547934-8d7c16ff8e3b?auto=format&fit=crop&w=500&q=80",
      desc: "Fitness bike with adjustable resistance.",
    },
    {
      id: 2,
      name: "Treadmill",
      priceNumber: 22,
      img: "https://images.unsplash.com/photo-1576678927484-cc907957088c?auto=format&fit=crop&w=500&q=80",
      desc: "Treadmill with speed and incline controls.",
    },
    {
      id: 3,
      name: "Cross Trainer",
      priceNumber: 18,
      img: "https://images.unsplash.com/photo-1517963879433-6ad2b056d712?auto=format&fit=crop&w=500&q=80",
      desc: "Compact cross trainer for full body workouts.",
    },
    {
      id: 4,
      name: "Rower",
      priceNumber: 15,
      img: "https://images.unsplash.com/photo-1599058917212-d750089bc07e?auto=format&fit=crop&w=500&q=80",
      desc: "Rowing machine for cardio training.",
    },
  ];

  const addToCart = (product) => {
    const existing = cartItems.find((item) => item.id === product.id);

    if (existing) {
      setCartItems(
        cartItems.map((item) =>
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        )
      );
    } else {
      setCartItems([...cartItems, { ...product, quantity: 1 }]);
    }

    setPage("cart");
  };

  return (
    <>
      <section className="shop-banner">
        <h1>Shop</h1>
      </section>

      <section className="fitness-intro">
        <p>Home / Fitness / Equipment</p>
        <h1>Equipment</h1>
        <p>Treadmill hire and rental is easy with our fitness equipment options.</p>
      </section>

      <section className="fitness-products">
        <div className="product-grid">
          {products.map((item) => (
            <div className="product" key={item.id}>
              <div className="product-image-box">
                <img src={item.img} alt={item.name} />
                <p>{item.desc}</p>
              </div>

              <h2>{item.name}</h2>
              <h3>${item.priceNumber.toFixed(2)} <span>per week *</span></h3>
              <button className="cart-btn" onClick={() => addToCart(item)}>
                ADD TO CART
              </button>
            </div>
          ))}
        </div>
      </section>
    </>
  );
}

function DeliveryAreas() {
  return (
    <>
      <section className="delivery-banner">
        <h1>Delivery Areas</h1>
      </section>

      <section className="delivery-page">
        <div className="callback-form">
          <h2>Request a callback</h2>
          <input placeholder="First Name" />
          <input placeholder="Email" />
          <input placeholder="Phone" />
          <textarea placeholder="Message"></textarea>
          <button>SUBMIT NOW</button>
        </div>

        <div className="map-section">
          <h2>📍 Find Your Delivery Region</h2>
          <input placeholder="Post Code or Suburb" />
          <iframe
            title="map"
            src="https://www.google.com/maps?q=New%20Zealand&output=embed"
            width="100%"
            height="430"
            style={{ border: 0 }}
          ></iframe>
        </div>
      </section>
    </>
  );
}

function Footer() {
  return (
    <footer>
      <div>
        <h2>Want to know more about our rentals?</h2>
        <h2>Join our mailing list!</h2>
        <input placeholder="First Name" />
        <input placeholder="Email Address" />
        <button>SUBSCRIBE</button>
      </div>

      <div>
        <h3>About</h3>
        <p>About Us</p>
        <p>Delivery Areas</p>
        <p>FAQs</p>
      </div>

      <div>
        <h3>Rental Solutions</h3>
        <p>Kitchen</p>
        <p>Laundry</p>
        <p>Furniture</p>
        <p>Fitness</p>
      </div>

      <div>
        <h3>Get In Touch</h3>
        <p>📞 0800 111 313</p>
      </div>
    </footer>
  );
}

export default App;
